int countNodes(struct Node *head) {
    int count = 0;
    struct Node *current = head;

    while(current != NULL) {
        count++;
        current = current->next;
    }

    return count;
}

int search(struct Node *head, int key) {
    struct Node *current = head;
    int position = 0;

    while(current != NULL) {
        if(current->data == key) {
            return position;
        }
        position++;
        current = current->next;
    }

    return -1;  // Not found
}
